+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import type { Trait } from '../../trait/types';
+import type { World } from '../../world';
+import type { EventType, QueryInstance, TrackingGroup } from '../types';
+import { checkQueryTrackingWithRelations } from './check-query-tracking-with-relations';
+
+/** Record a target-specific relation event for pair tracking modifiers. */
+export function setPairTracking(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    target: Entity,
+    eventType: EventType
+) {
+    const instance = world[$internal].traitInstances[trait.id];
+    if (!instance) return;
+
+    for (const query of instance.trackingQueries) {
+        let affected = false;
+        for (const group of query.trackingGroups) {
+            if (group.type !== eventType || !group.pairs.length) continue;
+            for (const pair of group.pairs) {
+                const pairCtx = pair[$internal];
+                if (pairCtx.relation[$internal].trait !== trait) continue;
+                if (pairCtx.target !== '*' && pairCtx.target !== target) continue;
+                updatePairTracker(group, entity, trait.id, target, eventType);
+                affected = true;
+            }
+        }
+        if (!affected) continue;
+
+        const match = checkQueryTrackingWithRelations(world, query, entity, eventType, -1, 0);
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
+
+function updatePairTracker(
+    group: TrackingGroup,
+    entity: Entity,
+    traitId: number,
+    target: Entity,
+    eventType: EventType
+) {
+    let entityPairs = group.pairTrackers.get(entity);
+    if (!entityPairs) group.pairTrackers.set(entity, (entityPairs = new Map()));
+    const key = `${traitId}:${target}`;
+    const previous = entityPairs.get(key) ?? 0;
+
+    if (eventType === 'change') {
+        entityPairs.set(key, 1);
+    } else if (eventType === 'add') {
+        entityPairs.set(key, previous === -1 ? 0 : 1);
+    } else {
+        entityPairs.set(key, previous === 1 ? 0 : -1);
+    }
+}
