    // Add symbol brand for fast type checking
    Object.defineProperty(relation, $relation, {
        value: true,
        writable: false,
        enumerable: false,
        configurable: false,
    });

    // Set the back-reference from trait to relation
    traitCtx.relation = relation;

    return relation;
